-- Enable fixed-dimension vector storage before creating retrieval columns.
CREATE EXTENSION IF NOT EXISTS vector;
-- Modify "sub_reports" table
ALTER TABLE "sub_reports" ADD COLUMN "retrieval_refs" jsonb NOT NULL DEFAULT '[]'::jsonb;
ALTER TABLE "sub_reports" ALTER COLUMN "retrieval_refs" DROP DEFAULT;
-- Create "retrieval_chunks" table
CREATE TABLE "retrieval_chunks" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "source_kind" character varying NOT NULL,
  "source_id" bigint NOT NULL,
  "source_ref" character varying NOT NULL,
  "content" text NOT NULL,
  "content_digest" character varying NOT NULL,
  "embedding_model" character varying NOT NULL,
  "embedding_dimensions" bigint NOT NULL,
  "embedding" vector(1536) NOT NULL,
  "metadata" jsonb NOT NULL,
  "created_at" timestamptz NOT NULL,
  PRIMARY KEY ("id")
);
-- Create index "retrievalchunk_embedding" to table: "retrieval_chunks"
CREATE INDEX "retrievalchunk_embedding" ON "retrieval_chunks" USING HNSW ("embedding" vector_cosine_ops);
-- Create index "retrievalchunk_embedding_model_created_at" to table: "retrieval_chunks"
CREATE INDEX "retrievalchunk_embedding_model_created_at" ON "retrieval_chunks" ("embedding_model", "created_at");
-- Create index "retrievalchunk_source_kind_source_id_embedding_model" to table: "retrieval_chunks"
CREATE UNIQUE INDEX "retrievalchunk_source_kind_source_id_embedding_model" ON "retrieval_chunks" ("source_kind", "source_id", "embedding_model");
